import json, collections
# Count sidechain vs main in a large session; also count isMeta
with open('/home/jwilger/projects/todo_list/.claude-sessions/ec2015cc-1f56-47bf-95cb-8416b28e659e.jsonl') as f:
    stats = {'main_user': 0, 'main_asst': 0, 'side_user': 0, 'side_asst': 0, 'meta': 0, 'system': 0, 'progress': 0, 'fhs': 0}
    for line in f:
        obj = json.loads(line)
        t = obj.get('type')
        sc = obj.get('isSidechain', False)
        meta = obj.get('isMeta', False)
        if t == 'file-history-snapshot':
            stats['fhs'] += 1
        elif t == 'system':
            stats['system'] += 1
        elif t == 'progress':
            stats['progress'] += 1
        elif t == 'user':
            if meta:
                stats['meta'] += 1
            elif sc:
                stats['side_user'] += 1
            else:
                stats['main_user'] += 1
        elif t == 'assistant':
            if sc:
                stats['side_asst'] += 1
            else:
                stats['main_asst'] += 1
    print(stats)
"

