import json
import os

# Scan for rare message types across a few files
sessions_dir = '/home/jwilger/projects/todo_list/.claude-sessions'
rare_types = set()
for fname in sorted(os.listdir(sessions_dir)):
    if fname.endswith('.jsonl') and '/' not in fname:
        fpath = os.path.join(sessions_dir, fname)
        try:
            with open(fpath) as f:
                for line in f:
                    obj = json.loads(line)
                    t = obj.get('type')
                    if t not in ('user', 'assistant', 'system', 'progress', 'file-history-snapshot'):
                        if t not in rare_types:
                            rare_types.add(t)
                            print(f'type={t} in {fname}')
                            print(f'  keys: {list(obj.keys())[:15]}')
                            print()
        except Exception as e:
            pass
        if len(rare_types) >= 5:
            break
" 2>&1

